0	//! Implementations of methods for [`AstNodes`].
1	
2	use oxc_span::{GetSpan, Span};
3	
4	use crate::ast_nodes::AstNodes;
5	
6	impl<'a> AstNodes<'a> {
7	    /// Returns an iterator over all ancestor nodes in the AST, starting from self.
8	    ///
9	    /// The iteration includes the current node and proceeds upward through the tree,
10	    /// terminating after yielding the root `Program` node.
11	    ///
12	    /// # Example hierarchy
13	    /// ```text
14	    /// Program
15	    ///   └─ BlockStatement
16	    ///       └─ ExpressionStatement  <- self
17	    /// ```
18	    /// For `self` as ExpressionStatement, this yields: [ExpressionStatement, BlockStatement, Program]
19	    pub fn ancestors(&self) -> impl Iterator<Item = &AstNodes<'a>> {
20	        // Start with the current node and walk up the tree, including Program
